sql:
SELECT COUNT(shipment_id) AS num_shipments, SUM(distance) AS total_distance
FROM shipments
WHERE status = 'In Transit' AND vehicle_id = 0;

SELECT action
FROM shipment_logs
WHERE user_id = 0;

SELECT s.from_location
FROM shipments s
WHERE s.dqf > (SELECT qm.threshold FROM quality_metrics qm WHERE qm.metric_name = 'Distance Quality Factor');

SELECT AVG(distance) AS average_distance
FROM shipments
WHERE status = 'In Transit' AND distance BETWEEN 1000 AND 2000 AND distance > 0;

SELECT AVG(distance) AS avg_distance, COUNT(*) AS shipment_count
FROM shipments
WHERE status = 'In Transit';

external_knowledge:
External knowledge:

* 'Top 5 longest shipments for each route' refers to the 5 shipments with the highest distance values for each combination of 'from_location' and 'to_location';
* The context assumes that a shipment with a higher distance is considered 'longer' than one with a lower distance.

sql:
SELECT COUNT(*) AS shipment_count
FROM shipments
WHERE driver_id = 1;

external_knowledge:
- 'In-transit shipments' refers to shipments with a status of 'In Transit'; 
- 'Within the last week' means between today's date and 7 days ago; 
- 'Within the next week' means between today's date and 7 days from now.

sql:
SELECT AVG(distance) AS average_shipment_distance
FROM shipments
WHERE driver_id = 1 AND status = 'Delivered';

SELECT AVG(s.distance) AS average_distance
FROM shipments s
WHERE s.status = 'Delivered' AND s.to_location = 'Retail Store B';

SELECT COUNT(shipment_id) AS num_shipments
FROM shipments
WHERE status = 'In Transit' AND dqf < 50;

SELECT DISTINCT status
FROM shipments
ORDER BY status;
